3	namespace App\Services;
4	
5	use App\Enums\InvoiceStatus;
6	use App\Enums\LineItemType;
7	use App\Models\Invoice;
8	use App\Models\InvoiceLineItem;
9	use App\Models\Settlement;
10	use App\Models\User;
11	use Illuminate\Support\Facades\DB;
12	use RuntimeException;
13	
14	class InvoiceService
15	{
16	    // ── Create ────────────────────────────────────────────────────────────────
17	
18	    /**
19	     * Create a DRAFT invoice with an auto-sequential number (MV-YYYY-NNNNN).
20	     *
21	     * Participates in the universal service-layer idempotency contract
22	     * (`docs/design.md:70-73`, audit Issue 3). Retries with the same key
23	     * return the existing draft rather than burning a second invoice
24	     * number in the MV-YYYY-NNNNN sequence — important because the numbers
25	     * are externally visible and gaps are harder to explain than retries.
26	     */
27	    public function createInvoice(User $user, string $idempotencyKey, ?string $notes = null): Invoice
28	    {
29	        $existing = Invoice::where('idempotency_key', $idempotencyKey)->first();
30	        if ($existing) {
31	            return $existing;
32	        }
33	
34	        return DB::transaction(function () use ($user, $notes, $idempotencyKey) {
35	            $number = $this->nextInvoiceNumber();
36	
37	            $invoice = Invoice::create([
38	                'user_id'         => $user->id,
39	                'invoice_number'  => $number,
40	                'total_cents'     => 0,
41	                'status'          => InvoiceStatus::DRAFT->value,
42	                'notes'           => $notes,
43	                'version'         => 1,
44	                'idempotency_key' => $idempotencyKey,
45	            ]);
46	
47	            AuditService::record('invoice.created', 'Invoice', $invoice->id, null, [
48	                'invoice_number' => $number,
49	                'user_id'        => $user->id,
50	            ]);
51	
52	            return $invoice;
53	        });
54	    }
55	
56	    // ── Line items ────────────────────────────────────────────────────────────
57	
58	    /**
59	     * Add a line item to a DRAFT invoice and recompute total.
60	     */
61	    public function addLineItem(
62	        Invoice $invoice,
63	        string $description,
64	        int $amountCents,
65	        LineItemType $type,
66	        ?string $referenceId = null
67	    ): InvoiceLineItem {
68	        if ($invoice->status !== InvoiceStatus::DRAFT) {
69	            throw new RuntimeException('Line items can only be added to DRAFT invoices.', 422);
70	        }
71	
72	        return DB::transaction(function () use ($invoice, $description, $amountCents, $type, $referenceId) {
73	            $sortOrder = $invoice->lineItems()->count() + 1;
74	
75	            $item = InvoiceLineItem::create([
76	                'invoice_id'   => $invoice->id,
77	                'description'  => $description,
78	                'amount_cents' => $amountCents,
79	                'line_type'    => $type->value,
80	                'reference_id' => $referenceId,
81	                'sort_order'   => $sortOrder,
82	            ]);
83	
84	            // Recompute total (item already persisted above, sum includes it)
85	            $invoice->total_cents = (int) $invoice->lineItems()->sum('amount_cents');
86	            $invoice->saveWithLock();
87	
88	            return $item;
89	        });
90	    }
91	
92	    // ── Issue ─────────────────────────────────────────────────────────────────
93	
94	    /**
95	     * Transition invoice DRAFT → ISSUED.
96	     */
97	    public function issueInvoice(Invoice $invoice): Invoice
98	    {
99	        if ($invoice->status !== InvoiceStatus::DRAFT) {
100	            throw new RuntimeException(
101	                "Cannot issue an invoice in {$invoice->status->value} status.",
102	                422
103	            );
104	        }
105	
106	        return DB::transaction(function () use ($invoice) {
107	            $before = $invoice->toArray();
108	
109	            $invoice->status    = InvoiceStatus::ISSUED;
110	            $invoice->issued_at = now();
111	            $invoice->saveWithLock();
112	
113	            AuditService::record('invoice.issued', 'Invoice', $invoice->id, $before, [
114	                'invoice_number' => $invoice->invoice_number,
115	            ]);
116	
117	            return $invoice;
118	        });
119	    }
120	
121	    // ── Mark paid ─────────────────────────────────────────────────────────────
122	
123	    /**
124	     * Transition invoice ISSUED → PAID.
125	     */
126	    public function markPaid(Invoice $invoice): Invoice
127	    {
128	        if ($invoice->status !== InvoiceStatus::ISSUED) {
129	            throw new RuntimeException(
130	                "Cannot mark paid an invoice in {$invoice->status->value} status.",
131	                422
132	            );
133	        }
134	
135	        return DB::transaction(function () use ($invoice) {
136	            $before = $invoice->toArray();
137	
138	            $invoice->status = InvoiceStatus::PAID;
139	            $invoice->saveWithLock();
140	
141	            AuditService::record('invoice.paid', 'Invoice', $invoice->id, $before, [
142	                'invoice_number' => $invoice->invoice_number,
143	            ]);
144	
145	            return $invoice;
146	        });
147	    }
148	
149	    // ── Void ──────────────────────────────────────────────────────────────────
150	
151	    /**
152	     * Void a DRAFT or ISSUED invoice. PAID → 422 (FIN-10).
153	     */
154	    public function voidInvoice(Invoice $invoice): Invoice
155	    {
156	        if ($invoice->status === InvoiceStatus::PAID) {
157	            throw new RuntimeException('Cannot void a PAID invoice.', 422);
158	        }
159	
160	        if (! in_array($invoice->status, [InvoiceStatus::DRAFT, InvoiceStatus::ISSUED], true)) {
161	            throw new RuntimeException(
162	                "Cannot void an invoice in {$invoice->status->value} status.",
163	                422
164	            );
165	        }
166	
167	        return DB::transaction(function () use ($invoice) {
168	            $before = $invoice->toArray();
169	
170	            $invoice->status = InvoiceStatus::VOIDED;
171	            $invoice->saveWithLock();
172	
173	            AuditService::record('invoice.voided', 'Invoice', $invoice->id, $before, [
174	                'invoice_number' => $invoice->invoice_number,
175	            ]);
176	
177	            return $invoice;
178	        });
179	    }
180	
181	    // ── Export statement ──────────────────────────────────────────────────────
182	
183	    /**
184	     * Delegate to SettlementService for statement export.
185	     */
186	    public function exportStatement(Settlement $settlement): string
187	    {
188	        return app(SettlementService::class)->exportStatement($settlement);
189	    }
190	
191	    // ── Private ───────────────────────────────────────────────────────────────
192	
193	    private function nextInvoiceNumber(): string
194	    {
195	        $year = now()->year;
196	        $prefix = "MV-{$year}-";
197	
198	        // Find highest sequential number for this year
199	        $last = Invoice::where('invoice_number', 'like', "{$prefix}%")
200	            ->orderByDesc('invoice_number')
201	            ->lockForUpdate()
202	            ->value('invoice_number');
203	
204	        $seq = $last ? ((int) substr($last, strlen($prefix))) + 1 : 1;
205	
206	        return $prefix . str_pad($seq, 5, '0', STR_PAD_LEFT);
207	    }
208	}
