3	namespace App\Services;
4	
5	use App\Enums\HoldReleaseReason;
6	use App\Enums\SignupStatus;
7	use App\Enums\TripStatus;
8	use App\Enums\WaitlistStatus;
9	use App\Events\TripStatusChanged;
10	use App\Exceptions\InvalidStatusTransitionException;
11	use App\Models\Trip;
12	use App\Models\User;
13	use App\Services\AuditService;
14	use Illuminate\Support\Facades\DB;
15	use RuntimeException;
16	
17	class TripService
18	{
19	    public function __construct(
20	        private readonly SeatService     $seatService,
21	        private readonly WaitlistService $waitlistService,
22	    ) {}
23	
24	    /**
25	     * Create a new trip in DRAFT status.
26	     *
27	     * Participates in the universal service-layer idempotency contract
28	     * (`docs/design.md:70-73`, audit Issue 3). Callers MUST pass a stable
29	     * `$idempotencyKey`. A retry with the same key short-circuits to the
30	     * existing row without creating a second draft. Combined with the
31	     * unique constraint on `trips.idempotency_key`, this collapses racing
32	     * double-submits onto one row instead of two.
33	     */
34	    public function create(array $data, User $creator, string $idempotencyKey): Trip
35	    {
36	        $existing = Trip::where('idempotency_key', $idempotencyKey)->first();
37	        if ($existing) {
38	            return $existing;
39	        }
40	
41	        $trip = Trip::create(array_merge($data, [
42	            'status'          => TripStatus::DRAFT->value,
43	            'available_seats' => $data['total_seats'],
44	            'booking_count'   => 0,
45	            'created_by'      => $creator->id,
46	            'idempotency_key' => $idempotencyKey,
47	        ]));
48	
49	        AuditService::record('trip.created', 'Trip', $trip->id, null, [
50	            'title'  => $trip->title,
51	            'status' => $trip->status->value,
52	        ]);
53	
54	        return $trip;
55	    }
56	
57	    /**
58	     * Update trip metadata (only allowed in DRAFT).
59	     */
60	    public function update(Trip $trip, array $data): Trip
61	    {
62	        if ($trip->status !== TripStatus::DRAFT) {
63	            throw new RuntimeException('Only DRAFT trips can be edited.', 422);
64	        }
65	
66	        $before = $trip->only(array_keys($data));
67	        $trip->fill($data);
68	
69	        // If total_seats changed, adjust available_seats proportionally
70	        if (isset($data['total_seats'])) {
71	            $delta = $data['total_seats'] - $trip->getOriginal('total_seats');
72	            $trip->available_seats = max(0, $trip->available_seats + $delta);
73	        }
74	
75	        $trip->saveWithLock();
76	
77	        AuditService::record('trip.updated', 'Trip', $trip->id, $before, $trip->only(array_keys($data)));
78	
79	        return $trip;
80	    }
81	
82	    /**
83	     * DRAFT → PUBLISHED. Requires an approved lead doctor.
84	     */
85	    public function publish(Trip $trip): Trip
86	    {
87	        $this->assertTransition($trip, TripStatus::PUBLISHED);
88	
89	        if (! $trip->doctor?->isApproved()) {
90	            throw new RuntimeException('Trip cannot be published: lead doctor is not credentialed.', 422);
91	        }
92	
93	        return $this->transition($trip, TripStatus::PUBLISHED, 'trip.published');
94	    }
95	
96	    /**
97	     * Close a trip for new signups (PUBLISHED/FULL → CLOSED).
98	     */
99	    public function close(Trip $trip): Trip
100	    {
101	        $this->assertTransition($trip, TripStatus::CLOSED);
102	
103	        return $this->transition($trip, TripStatus::CLOSED, 'trip.closed');
104	    }
105	
106	    /**
107	     * Cancel a trip — cascades to all active signups and waitlist entries.
108	     */
109	    public function cancel(Trip $trip, User $actor): Trip
110	    {
111	        $this->assertTransition($trip, TripStatus::CANCELLED);
112	
113	        DB::transaction(function () use ($trip, $actor) {
114	            // Decline all waitlist entries FIRST — prevents offerNextSeat firing
115	            // during the hold releases below and broadcasting spurious offers
116	            $trip->waitlistEntries()
117	                ->whereIn('status', [WaitlistStatus::WAITING->value, WaitlistStatus::OFFERED->value])
118	                ->each(function ($entry) {
119	                    $entry->status = WaitlistStatus::DECLINED;
120	                    $entry->save();
121	                });
122	
123	            // Release all HOLD signups (seats go back; offerNextSeat is a no-op
124	            // now that all waitlist entries are already DECLINED)
125	            $trip->signups()->where('status', SignupStatus::HOLD->value)->each(
126	                fn ($signup) => $this->seatService->releaseSeat($signup, HoldReleaseReason::CANCELLED)
127	            );
128	
129	            // Cancel all CONFIRMED signups
130	            $trip->signups()->where('status', SignupStatus::CONFIRMED->value)->each(function ($signup) {
131	                $before = ['status' => $signup->status->value];
132	                $signup->status       = SignupStatus::CANCELLED;
133	                $signup->cancelled_at = now();
134	                $signup->saveWithLock();
135	                AuditService::record('trip_signup.cancelled_by_trip', 'TripSignup', $signup->id, $before, [
136	                    'status' => SignupStatus::CANCELLED->value,
137	                ]);
138	            });
139	
140	            $this->transition($trip, TripStatus::CANCELLED, 'trip.cancelled');
141	        });
142	
143	        return $trip->fresh();
144	    }
145	
146	    // ── Private helpers ────────────────────────────────────────────────────────
147	
148	    private function assertTransition(Trip $trip, TripStatus $to): void
149	    {
150	        if (! in_array($to, $trip->status->allowedTransitions(), true)) {
151	            throw new InvalidStatusTransitionException(
152	                from: $trip->status->value,
153	                to:   $to->value,
154	                entity: 'Trip',
155	            );
156	        }
157	    }
158	
159	    private function transition(Trip $trip, TripStatus $newStatus, string $auditAction): Trip
160	    {
161	        $before         = ['status' => $trip->status->value];
162	        $trip->status   = $newStatus;
163	        $trip->saveWithLock();
164	
165	        AuditService::record($auditAction, 'Trip', $trip->id, $before, ['status' => $newStatus->value]);
166	
167	        TripStatusChanged::dispatch($trip->fresh());
168	
169	        return $trip;
170	    }
171	}
