3	namespace App\Services;
4	
5	use App\Enums\ReviewStatus;
6	use App\Enums\SignupStatus;
7	use App\Models\Trip;
8	use App\Models\TripReview;
9	use App\Models\User;
10	use Illuminate\Support\Facades\DB;
11	use RuntimeException;
12	
13	class ReviewService
14	{
15	    /**
16	     * REV-01: user must have a CONFIRMED signup on a trip that has already ended.
17	     * REV-02: one review per user per trip.
18	     *
19	     * Participates in the universal service-layer idempotency contract
20	     * (`docs/design.md:70-73`, audit Issue 3). The REV-02 natural-key guard
21	     * catches the "already reviewed" case at the logical level, but an
22	     * explicit `$idempotencyKey` lets genuine retries (double-click, network
23	     * blip) return the first review instead of throwing a 422.
24	     */
25	    public function create(Trip $trip, User $user, int $rating, ?string $text, string $idempotencyKey): TripReview
26	    {
27	        $existingByKey = TripReview::where('idempotency_key', $idempotencyKey)->first();
28	        if ($existingByKey) {
29	            return $existingByKey;
30	        }
31	
32	        $this->assertEligible($trip, $user);
33	        $this->assertRating($rating);
34	
35	        return DB::transaction(function () use ($trip, $user, $rating, $text, $idempotencyKey) {
36	            $review = TripReview::create([
37	                'trip_id'         => $trip->id,
38	                'user_id'         => $user->id,
39	                'rating'          => $rating,
40	                'review_text'     => $text,
41	                'status'          => ReviewStatus::ACTIVE->value,
42	                'version'         => 1,
43	                'idempotency_key' => $idempotencyKey,
44	            ]);
45	
46	            $this->recomputeAverageRating($trip);
47	
48	            AuditService::record('review.created', 'TripReview', $review->id, null, [
49	                'trip_id' => $trip->id,
50	                'rating'  => $rating,
51	            ]);
52	
53	            return $review;
54	        });
55	    }
56	
57	    /**
58	     * Author may update their own ACTIVE review.
59	     */
60	    public function update(TripReview $review, User $author, int $rating, ?string $text): TripReview
61	    {
62	        if ($review->user_id !== $author->id) {
63	            throw new RuntimeException('You can only edit your own review.', 403);
64	        }
65	
66	        if ($review->status !== ReviewStatus::ACTIVE) {
67	            throw new RuntimeException('Only ACTIVE reviews can be edited.', 422);
68	        }
69	
70	        $this->assertRating($rating);
71	
72	        return DB::transaction(function () use ($review, $rating, $text) {
73	            $before = ['rating' => $review->rating, 'review_text' => $review->review_text];
74	
75	            $review->rating      = $rating;
76	            $review->review_text = $text;
77	            $review->saveWithLock();
78	
79	            $this->recomputeAverageRating($review->trip);
80	
81	            AuditService::record('review.updated', 'TripReview', $review->id, $before, [
82	                'rating'      => $rating,
83	                'review_text' => $text,
84	            ]);
85	
86	            return $review->fresh();
87	        });
88	    }
89	
90	    /**
91	     * Admin: flag a review — hides it from the trip page.
92	     */
93	    public function flag(TripReview $review): TripReview
94	    {
95	        if ($review->status !== ReviewStatus::ACTIVE) {
96	            throw new RuntimeException('Only ACTIVE reviews can be flagged.', 422);
97	        }
98	
99	        return DB::transaction(function () use ($review) {
100	            $before         = ['status' => $review->status->value];
101	            $review->status = ReviewStatus::FLAGGED;
102	            $review->saveWithLock();
103	
104	            $this->recomputeAverageRating($review->trip);
105	
106	            AuditService::record('review.flagged', 'TripReview', $review->id, $before, [
107	                'status' => ReviewStatus::FLAGGED->value,
108	            ]);
109	
110	            return $review->fresh();
111	        });
112	    }
113	
114	    /**
115	     * Admin: permanently remove a review.
116	     */
117	    public function remove(TripReview $review): TripReview
118	    {
119	        if ($review->status === ReviewStatus::REMOVED) {
120	            throw new RuntimeException('Review is already removed.', 422);
121	        }
122	
123	        return DB::transaction(function () use ($review) {
124	            $before         = ['status' => $review->status->value];
125	            $review->status = ReviewStatus::REMOVED;
126	            $review->saveWithLock();
127	
128	            $this->recomputeAverageRating($review->trip);
129	
130	            AuditService::record('review.removed', 'TripReview', $review->id, $before, [
131	                'status' => ReviewStatus::REMOVED->value,
132	            ]);
133	
134	            return $review->fresh();
135	        });
136	    }
137	
138	    // ── Private helpers ────────────────────────────────────────────────────────
139	
140	    /**
141	     * REV-01 + REV-02 eligibility checks.
142	     */
143	    private function assertEligible(Trip $trip, User $user): void
144	    {
145	        // REV-01: must have a CONFIRMED signup
146	        $hasConfirmedSignup = $trip->signups()
147	            ->where('user_id', $user->id)
148	            ->where('status', SignupStatus::CONFIRMED->value)
149	            ->exists();
150	
151	        if (! $hasConfirmedSignup) {
152	            throw new RuntimeException(
153	                'You can only review trips you have attended (must have a confirmed signup).',
154	                422
155	            );
156	        }
157	
158	        // REV-01: trip must have ended
159	        if (! $trip->end_date->isPast()) {
160	            throw new RuntimeException(
161	                'You can only review a trip after it has ended.',
162	                422
163	            );
164	        }
165	
166	        // REV-02: one review per user per trip
167	        $alreadyReviewed = TripReview::where('trip_id', $trip->id)
168	            ->where('user_id', $user->id)
169	            ->whereNot('status', ReviewStatus::REMOVED->value)
170	            ->exists();
171	
172	        if ($alreadyReviewed) {
173	            throw new RuntimeException(
174	                'You have already submitted a review for this trip.',
175	                422
176	            );
177	        }
178	    }
179	
180	    private function assertRating(int $rating): void
181	    {
182	        if ($rating < 1 || $rating > 5) {
183	            throw new RuntimeException('Rating must be between 1 and 5.', 422);
184	        }
185	    }
186	
187	    /**
188	     * Recompute the trip's average_rating from all ACTIVE reviews,
189	     * then persist. Null when there are no active reviews.
190	     */
191	    public function recomputeAverageRating(Trip $trip): void
192	    {
193	        $avg = TripReview::where('trip_id', $trip->id)
194	            ->where('status', ReviewStatus::ACTIVE->value)
195	            ->avg('rating');
196	
197	        // Use raw update to bypass optimistic locking — this is a derived value
198	        Trip::where('id', $trip->id)->update([
199	            'average_rating' => $avg !== null ? round((float) $avg, 2) : null,
200	        ]);
201	    }
202	}
