3	namespace App\Services;
4	
5	use App\Enums\HoldReleaseReason;
6	use App\Enums\SignupStatus;
7	use App\Enums\TripStatus;
8	use App\Events\SeatHeld;
9	use App\Events\SeatReleased;
10	use App\Events\SignupConfirmed;
11	use App\Jobs\NotifyHoldExpiring;
12	use App\Jobs\ReleaseExpiredHold;
13	use App\Models\SeatHold;
14	use App\Models\Trip;
15	use App\Models\TripSignup;
16	use App\Models\User;
17	use App\Services\AuditService;
18	use Illuminate\Support\Facades\DB;
19	use RuntimeException;
20	
21	class SeatService
22	{
23	    public function __construct(
24	        private readonly WaitlistService $waitlistService,
25	    ) {}
26	
27	    /**
28	     * TRIP-05/06: Atomically decrement available_seats and create a 10-min hold.
29	     * Uses SELECT FOR UPDATE to prevent overselling.
30	     *
31	     * @throws RuntimeException (422) when no seats available or user already has active signup
32	     */
33	    public function holdSeat(Trip $trip, User $user, string $idempotencyKey): TripSignup
34	    {
35	        // Idempotency: if a signup was already created for this key, return it
36	        // immediately without entering the transaction. This makes double-clicks,
37	        // Livewire re-renders, and network retries collapse onto the same hold.
38	        $existing = TripSignup::where('idempotency_key', $idempotencyKey)->first();
39	        if ($existing) {
40	            return $existing;
41	        }
42	
43	        return DB::transaction(function () use ($trip, $user, $idempotencyKey) {
44	            // Lock the trip row for the duration of this transaction
45	            $trip = Trip::lockForUpdate()->findOrFail($trip->id);
46	
47	            // TRIP-09: reject if user already has an active signup or waitlist entry
48	            $existing = TripSignup::where('trip_id', $trip->id)
49	                ->where('user_id', $user->id)
50	                ->whereIn('status', [SignupStatus::HOLD->value, SignupStatus::CONFIRMED->value])
51	                ->exists();
52	
53	            if ($existing) {
54	                throw new RuntimeException('You already have an active signup for this trip.', 422);
55	            }
56	
57	            // TRIP-06: no seats available
58	            if ($trip->available_seats <= 0 || $trip->status !== TripStatus::PUBLISHED) {
59	                throw new RuntimeException('No seats are currently available for this trip.', 422);
60	            }
61	
62	            $holdMinutes = (int) config('medvoyage.seat_hold_minutes', 10);
63	            $expiresAt   = now()->addMinutes($holdMinutes);
64	
65	            // Create the signup record
66	            $signup = TripSignup::create([
67	                'trip_id'          => $trip->id,
68	                'user_id'          => $user->id,
69	                'status'           => SignupStatus::HOLD->value,
70	                'hold_expires_at'  => $expiresAt,
71	                'idempotency_key'  => $idempotencyKey,
72	                'version'          => 1,
73	            ]);
74	
75	            // Record seat hold metadata
76	            SeatHold::create([
77	                'trip_id'   => $trip->id,
78	                'signup_id' => $signup->id,
79	                'held_at'   => now(),
80	                'expires_at' => $expiresAt,
81	            ]);
82	
83	            // Decrement available seats
84	            $trip->decrement('available_seats');
85	            $trip->refresh();
86	
87	            // TRIP-06: if seats hit 0, transition trip to FULL
88	            if ($trip->available_seats === 0 && $trip->status === TripStatus::PUBLISHED) {
89	                $trip->status = TripStatus::FULL;
90	                $trip->saveWithLock();
91	            }
92	
93	            AuditService::record('trip_signup.hold_created', 'TripSignup', $signup->id, null, [
94	                'trip_id'        => $trip->id,
95	                'user_id'        => $user->id,
96	                'hold_expires_at' => $expiresAt->toIso8601String(),
97	            ]);
98	
99	            SeatHeld::dispatch($trip->fresh());
100	
101	            // Real-time expiry: schedule the broadcast warning (T-2min) and the
102	            // hard release (T=expiry) as delayed queue jobs. These replace the
103	            // old `medvoyage:expire-seat-holds` polling loop with precise,
104	            // event-driven scheduling — see docs/questions.md §1.1. The cron
105	            // command still runs on a slower cadence as a safety net in case
106	            // the queue worker is down.
107	            //
108	            // Dispatched *inside* the transaction rather than via afterCommit
109	            // because test runs wrap each case in an outer RefreshDatabase
110	            // transaction that never commits — afterCommit would silently
111	            // drop the dispatch and mask real bugs. If this transaction rolls
112	            // back in production, both jobs re-fetch the signup by id on
113	            // execution and no-op when it doesn't exist.
114	            $warnAt = $expiresAt->copy()->subMinutes(2);
115	            if ($warnAt->isFuture()) {
116	                NotifyHoldExpiring::dispatch($signup->id)->delay($warnAt);
117	            }
118	            ReleaseExpiredHold::dispatch($signup->id)->delay($expiresAt);
119	
120	            return $signup;
121	        });
122	    }
123	
124	    /**
125	     * Confirm a hold — links a payment and transitions status to CONFIRMED.
126	     */
127	    public function confirmSeat(TripSignup $signup, string $paymentId): TripSignup
128	    {
129	        if ($signup->status !== SignupStatus::HOLD) {
130	            throw new RuntimeException('Only HOLD signups can be confirmed.', 422);
131	        }
132	
133	        if ($signup->isHoldExpired()) {
134	            throw new RuntimeException('Hold has expired. Please restart the booking.', 422);
135	        }
136	
137	        return DB::transaction(function () use ($signup, $paymentId) {
138	            $before = ['status' => $signup->status->value];
139	
140	            $signup->status       = SignupStatus::CONFIRMED;
141	            $signup->confirmed_at = now();
142	            $signup->payment_id   = $paymentId;
143	            $signup->saveWithLock();
144	
145	            // Mark the hold as released (confirmed)
146	            $signup->hold?->update([
147	                'released'       => true,
148	                'released_at'    => now(),
149	                'release_reason' => HoldReleaseReason::CONFIRMED->value,
150	            ]);
151	
152	            // Increment booking count on the trip
153	            $signup->trip()->increment('booking_count');
154	            $trip = $signup->trip()->first();
155	
156	            AuditService::record('trip_signup.confirmed', 'TripSignup', $signup->id, $before, [
157	                'status'     => SignupStatus::CONFIRMED->value,
158	                'payment_id' => $paymentId,
159	            ]);
160	
161	            SignupConfirmed::dispatch($trip, $signup->fresh());
162	
163	            return $signup->fresh();
164	        });
165	    }
166	
167	    /**
168	     * Release a seat — restores available_seats, marks hold as released,
169	     * and triggers waitlist offer if applicable.
170	     */
171	    public function releaseSeat(TripSignup $signup, HoldReleaseReason $reason): void
172	    {
173	        DB::transaction(function () use ($signup, $reason) {
174	            $trip = Trip::lockForUpdate()->findOrFail($signup->trip_id);
175	
176	            $before = ['status' => $signup->status->value];
177	
178	            $newStatus = match ($reason) {
179	                HoldReleaseReason::EXPIRED    => SignupStatus::EXPIRED,
180	                HoldReleaseReason::CANCELLED  => SignupStatus::CANCELLED,
181	                default                       => SignupStatus::EXPIRED,
182	            };
183	
184	            $signup->status       = $newStatus;
185	            $signup->cancelled_at = now();
186	            $signup->saveWithLock();
187	
188	            // Mark hold as released
189	            $signup->hold?->update([
190	                'released'       => true,
191	                'released_at'    => now(),
192	                'release_reason' => $reason->value,
193	            ]);
194	
195	            // Restore seat count
196	            $trip->increment('available_seats');
197	            $trip->refresh();
198	
199	            // If trip was FULL, transition back to PUBLISHED
200	            if ($trip->status === TripStatus::FULL && $trip->available_seats > 0) {
201	                $trip->status = TripStatus::PUBLISHED;
202	                $trip->saveWithLock();
203	            }
204	
205	            AuditService::record('trip_signup.seat_released', 'TripSignup', $signup->id, $before, [
206	                'status' => $newStatus->value,
207	                'reason' => $reason->value,
208	            ]);
209	
210	            SeatReleased::dispatch($trip->fresh());
211	
212	            // Offer to next in waitlist
213	            $this->waitlistService->offerNextSeat($trip->fresh());
214	        });
215	    }
216	
217	    /**
218	     * Cancel a confirmed signup — decrements booking_count and releases the seat.
219	     */
220	    public function cancelConfirmedSignup(TripSignup $signup): void
221	    {
222	        if ($signup->status !== SignupStatus::CONFIRMED) {
223	            throw new RuntimeException('Only CONFIRMED signups can be cancelled.', 422);
224	        }
225	
226	        DB::transaction(function () use ($signup) {
227	            $trip = Trip::lockForUpdate()->findOrFail($signup->trip_id);
228	
229	            $before = ['status' => $signup->status->value];
230	
231	            $signup->status       = SignupStatus::CANCELLED;
232	            $signup->cancelled_at = now();
233	            $signup->saveWithLock();
234	
235	            $trip->decrement('booking_count');
236	            $trip->increment('available_seats');
237	            $trip->refresh();
238	
239	            if ($trip->status === TripStatus::FULL && $trip->available_seats > 0) {
240	                $trip->status = TripStatus::PUBLISHED;
241	                $trip->saveWithLock();
242	            }
243	
244	            AuditService::record('trip_signup.cancelled', 'TripSignup', $signup->id, $before, [
245	                'status' => SignupStatus::CANCELLED->value,
246	            ]);
247	
248	            SeatReleased::dispatch($trip->fresh());
249	            $this->waitlistService->offerNextSeat($trip->fresh());
250	        });
251	    }
252	}
