3	namespace App\Services;
4	
5	use App\Enums\DocumentType;
6	use App\Models\Doctor;
7	use App\Models\DoctorDocument;
8	use App\Models\User;
9	use App\Services\AuditService;
10	use Illuminate\Http\UploadedFile;
11	use Illuminate\Support\Facades\Storage;
12	use Illuminate\Support\Str;
13	use RuntimeException;
14	
15	class DocumentService
16	{
17	    private const MAX_BYTES    = 10 * 1024 * 1024; // 10 MB
18	    private const ALLOWED_MIME = ['application/pdf', 'image/jpeg', 'image/png'];
19	    private const ALLOWED_EXT  = ['pdf', 'jpeg', 'jpg', 'png'];
20	
21	    /**
22	     * Validate, store, and record a document upload.
23	     *
24	     * CRED-02: PDF/JPEG/PNG only, max 10 MB.
25	     * CRED-03: SHA-256 duplicate check per doctor + doc_type.
26	     *
27	     * @throws RuntimeException (HTTP 422) on validation failure
28	     */
29	    public function upload(
30	        Doctor       $doctor,
31	        UploadedFile $file,
32	        DocumentType $type,
33	        User         $uploader,
34	    ): DoctorDocument {
35	        // ── File type validation ──────────────────────────────────────────────
36	        $mime = $file->getMimeType();
37	        $ext  = strtolower($file->getClientOriginalExtension());
38	
39	        if (! in_array($mime, self::ALLOWED_MIME, true) || ! in_array($ext, self::ALLOWED_EXT, true)) {
40	            throw new RuntimeException('Only PDF, JPEG, and PNG files are accepted.', 422);
41	        }
42	
43	        // ── File size validation ──────────────────────────────────────────────
44	        if ($file->getSize() > self::MAX_BYTES) {
45	            throw new RuntimeException('File size must not exceed 10 MB.', 422);
46	        }
47	
48	        // ── Checksum ──────────────────────────────────────────────────────────
49	        $checksum = hash_file('sha256', $file->getRealPath());
50	
51	        // CRED-03: reject duplicate checksum for same doctor + type
52	        if (DoctorDocument::where('doctor_id', $doctor->id)
53	                ->where('document_type', $type->value)
54	                ->where('checksum', $checksum)
55	                ->exists()
56	        ) {
57	            throw new RuntimeException('A document with identical content already exists for this type.', 422);
58	        }
59	
60	        // ── Store file ────────────────────────────────────────────────────────
61	        $uuid     = (string) Str::uuid();
62	        $filename = "{$uuid}.{$ext}";
63	        $path     = "documents/{$doctor->id}/{$filename}";
64	
65	        Storage::disk('local')->put($path, file_get_contents($file->getRealPath()));
66	
67	        // ── Record ────────────────────────────────────────────────────────────
68	        $doc = DoctorDocument::create([
69	            'doctor_id'     => $doctor->id,
70	            'document_type' => $type->value,
71	            'file_path'     => $path,
72	            'file_name'     => $file->getClientOriginalName(),
73	            'file_size'     => $file->getSize(),
74	            'mime_type'     => $mime,
75	            'checksum'      => $checksum,
76	            'uploaded_by'   => $uploader->id,
77	        ]);
78	
79	        AuditService::record(
80	            'doctor_document.uploaded',
81	            'DoctorDocument',
82	            $doc->id,
83	            null,
84	            ['type' => $type->value, 'doctor_id' => $doctor->id],
85	        );
86	
87	        return $doc;
88	    }
89	
90	    /**
91	     * Determine whether a user may download a document.
92	     * Allowed: the doctor themselves, the assigned reviewer, or any admin.
93	     */
94	    public function canDownload(DoctorDocument $doc, User $user): bool
95	    {
96	        if ($user->isAdmin()) {
97	            return true;
98	        }
99	
100	        // Is the user the doctor?
101	        if ($doc->doctor->user_id === $user->id) {
102	            return true;
103	        }
104	
105	        // Is the user the assigned reviewer on the active case?
106	        $activeCase = $doc->doctor->activeCase();
107	        if ($activeCase && $activeCase->assigned_reviewer === $user->id) {
108	            return true;
109	        }
110	
111	        return false;
112	    }
113	
114	    /**
115	     * Authorize, audit, and return a download response for a doctor document.
116	     *
117	     * Every download call emits a `doctor_document.downloaded` audit entry
118	     * (audit Issue 5 — export traceability). Authorization is enforced here
119	     * so the route is a one-liner and no caller can emit the file without
120	     * passing through the audit hook.
121	     *
122	     * @throws RuntimeException 403 if the user is not permitted to download,
123	     *                          404 if the underlying file is missing.
124	     */
125	    public function download(DoctorDocument $doc, User $user): \Symfony\Component\HttpFoundation\StreamedResponse
126	    {
127	        if (! $this->canDownload($doc, $user)) {
128	            throw new RuntimeException('You are not authorised to download this document.', 403);
129	        }
130	
131	        if (! Storage::disk('local')->exists($doc->file_path)) {
132	            throw new RuntimeException('File not found.', 404);
133	        }
134	
135	        AuditService::record(
136	            action:     'doctor_document.downloaded',
137	            entityType: 'DoctorDocument',
138	            entityId:   $doc->id,
139	            before:     null,
140	            after:      [
141	                'doctor_id'     => $doc->doctor_id,
142	                'document_type' => $doc->document_type instanceof \BackedEnum
143	                                    ? $doc->document_type->value
144	                                    : $doc->document_type,
145	                'file_name'     => $doc->file_name,
146	                'checksum'      => $doc->checksum,
147	            ],
148	        );
149	
150	        return Storage::disk('local')->download($doc->file_path, $doc->file_name, [
151	            'Content-Type' => $doc->mime_type,
152	        ]);
153	    }
154	}
