5	use App\Enums\OrderStatus;
6	use App\Enums\OrderType;
7	use App\Enums\RefundStatus;
8	use App\Enums\RefundType;
9	use App\Models\MembershipOrder;
10	use App\Models\MembershipPlan;
11	use App\Models\Refund;
12	use App\Models\User;
13	use Illuminate\Support\Facades\DB;
14	use RuntimeException;
15	
16	class MembershipService
17	{
18	    // ── Purchase ───────────────────────────────────────────────────────────────
19	
20	    /**
21	     * Create a new PENDING membership order.
22	     * questions.md 3.2: only allowed when the user has NO currently active membership.
23	     */
24	    public function purchase(User $user, MembershipPlan $plan, string $idempotencyKey): MembershipOrder
25	    {
26	        // Idempotency: return existing order for this key
27	        if ($existing = MembershipOrder::where('idempotency_key', $idempotencyKey)->first()) {
28	            return $existing;
29	        }
30	
31	        if ($user->activeMembership() !== null) {
32	            throw new RuntimeException(
33	                'You already have an active membership. Renew or upgrade instead.',
34	                422
35	            );
36	        }
37	
38	        if (! $plan->is_active) {
39	            throw new RuntimeException('This membership plan is no longer available.', 422);
40	        }
41	
42	        return DB::transaction(function () use ($user, $plan, $idempotencyKey) {
43	            $now      = now();
44	            $expiresAt = $now->copy()->addMonths($plan->duration_months);
45	
46	            $order = MembershipOrder::create([
47	                'user_id'               => $user->id,
48	                'plan_id'               => $plan->id,
49	                'order_type'            => OrderType::PURCHASE->value,
50	                'amount_cents'          => $plan->price_cents,
51	                'status'                => OrderStatus::PENDING->value,
52	                'starts_at'             => $now,
53	                'expires_at'            => $expiresAt,
54	                'top_up_eligible_until' => $now->copy()->addDays(30),
55	                'idempotency_key'       => $idempotencyKey,
56	            ]);
57	
58	            AuditService::record('membership.purchased', 'MembershipOrder', $order->id, null, [
59	                'plan_id' => $plan->id,
60	                'tier'    => $plan->tier->value,
61	                'amount'  => $plan->price_cents,
62	            ]);
63	
64	            return $order;
65	        });
66	    }
67	
68	    // ── Renew ──────────────────────────────────────────────────────────────────
69	
70	    /**
71	     * MEM-02: Extend from current expires_at (or now if already expired).
72	     */
73	    public function renew(User $user, MembershipPlan $plan, string $idempotencyKey): MembershipOrder
74	    {
75	        if ($existing = MembershipOrder::where('idempotency_key', $idempotencyKey)->first()) {
76	            return $existing;
77	        }
78	
79	        if (! $plan->is_active) {
80	            throw new RuntimeException('This membership plan is no longer available.', 422);
81	        }
82	
83	        return DB::transaction(function () use ($user, $plan, $idempotencyKey) {
84	            $current   = $user->activeMembership();
85	            $baseDate  = ($current && $current->expires_at->isFuture())
86	                ? $current->expires_at
87	                : now();
88	
89	            $expiresAt = $baseDate->copy()->addMonths($plan->duration_months);
90	
91	            $order = MembershipOrder::create([
92	                'user_id'               => $user->id,
93	                'plan_id'               => $plan->id,
94	                'order_type'            => OrderType::RENEWAL->value,
95	                'amount_cents'          => $plan->price_cents,
96	                'status'                => OrderStatus::PENDING->value,
97	                'starts_at'             => now(),
98	                'expires_at'            => $expiresAt,
99	                'top_up_eligible_until' => now()->addDays(30),
100	                'idempotency_key'       => $idempotencyKey,
101	            ]);
102	
103	            AuditService::record('membership.renewed', 'MembershipOrder', $order->id, null, [
104	                'plan_id'    => $plan->id,
105	                'expires_at' => $expiresAt->toIso8601String(),
106	            ]);
107	
108	            return $order;
109	        });
110	    }
111	
112	    // ── Top-up ─────────────────────────────────────────────────────────────────
113	
114	    /**
115	     * questions.md 3.1 / MEM-03 / MEM-04:
116	     * - Only within 30 days of original purchase.
117	     * - Only to a higher tier (upgrade, not downgrade).
118	     * - New order amount = new plan price − current plan price.
119	     * - New order expires_at = current order expires_at (keeps original duration).
120	     */
121	    public function topUp(User $user, MembershipPlan $newPlan, string $idempotencyKey): MembershipOrder
122	    {
123	        if ($existing = MembershipOrder::where('idempotency_key', $idempotencyKey)->first()) {
124	            return $existing;
125	        }
126	
127	        $current = $user->activeMembership();
128	
129	        if ($current === null) {
130	            throw new RuntimeException('You need an active membership to perform an upgrade.', 422);
131	        }
132	
133	        if (! $current->isTopUpEligible()) {
134	            throw new RuntimeException(
135	                'The 30-day upgrade window for your current plan has expired.',
136	                422
137	            );
138	        }
139	
140	        $currentTier = $current->plan->tier;
141	        $newTier     = $newPlan->tier;
142	
143	        if (! $newTier->isHigherThan($currentTier)) {
144	            throw new RuntimeException(
145	                "Cannot downgrade from {$currentTier->label()} to {$newTier->label()}. Only upgrades are allowed.",
146	                422
147	            );
148	        }
149	
150	        if (! $newPlan->is_active) {
151	            throw new RuntimeException('This membership plan is no longer available.', 422);
152	        }
153	
154	        return DB::transaction(function () use ($user, $current, $newPlan, $idempotencyKey) {
155	            $priceDiff = max(0, $newPlan->price_cents - $current->plan->price_cents);
156	
157	            $order = MembershipOrder::create([
158	                'user_id'               => $user->id,
159	                'plan_id'               => $newPlan->id,
160	                'order_type'            => OrderType::TOP_UP->value,
161	                'amount_cents'          => $priceDiff,
162	                'previous_order_id'     => $current->id,
163	                'status'                => OrderStatus::PENDING->value,
164	                'starts_at'             => now(),
165	                'expires_at'            => $current->expires_at, // keeps original duration
166	                'top_up_eligible_until' => null,                  // no further top-ups on top-ups
167	                'idempotency_key'       => $idempotencyKey,
168	            ]);
169	
170	            AuditService::record('membership.topped_up', 'MembershipOrder', $order->id, null, [
171	                'from_plan'  => $current->plan_id,
172	                'to_plan'    => $newPlan->id,
173	                'amount'     => $priceDiff,
174	                'expires_at' => $current->expires_at->toIso8601String(),
175	            ]);
176	
177	            return $order;
178	        });
179	    }
180	
181	    // ── Refund ─────────────────────────────────────────────────────────────────
182	
183	    /**
184	     * questions.md 3.3: Refunds are per-order, not per-lifecycle.
185	     * The order must be PAID and must have a linked payment.
186	     */
187	    public function requestRefund(
188	        MembershipOrder $order,
189	        RefundType      $type,
190	        string          $reason,
191	        ?int            $amountCents = null,
192	        string          $idempotencyKey = '',
193	        ?string         $actorId = null,
194	    ): Refund {
195	        if ($actorId !== null && (string) $order->user_id !== $actorId) {
196	            throw new RuntimeException('You are not authorised to refund this order.', 403);
197	        }
198	
199	        if ($existing = Refund::where('idempotency_key', $idempotencyKey)->first()) {
200	            return $existing;
201	        }
202	
203	        if ($order->status !== OrderStatus::PAID) {
204	            throw new RuntimeException('Only PAID orders can be refunded.', 422);
205	        }
206	
207	        if (! $order->payment_id) {
208	            throw new RuntimeException('This order has no linked payment record.', 422);
209	        }
210	
211	        if ($type === RefundType::PARTIAL) {
212	            if ($amountCents === null || $amountCents <= 0 || $amountCents >= $order->amount_cents) {
213	                throw new RuntimeException(
214	                    'Partial refund amount must be greater than 0 and less than the order total.',
215	                    422
216	                );
217	            }
218	        }
219	
220	        if (strlen(trim($reason)) < 10) {
221	            throw new RuntimeException('Refund reason must be at least 10 characters.', 422);
222	        }
223	
224	        return DB::transaction(function () use ($order, $type, $reason, $amountCents, $idempotencyKey) {
225	            $refundAmount = $type === RefundType::FULL
226	                ? $order->amount_cents
227	                : $amountCents;
228	
229	            $refund = Refund::create([
230	                'payment_id'      => $order->payment_id,
231	                'amount_cents'    => $refundAmount,
232	                'refund_type'     => $type->value,
233	                'reason'          => $reason,
234	                'status'          => RefundStatus::PENDING->value,
235	                'idempotency_key' => $idempotencyKey,
236	            ]);
237	
238	            AuditService::record('refund.requested', 'Refund', $refund->id, null, [
239	                'order_id' => $order->id,
240	                'type'     => $type->value,
241	                'amount'   => $refundAmount,
242	            ]);
243	
244	            return $refund;
245	        });
246	    }
247	
248	    /**
249	     * Finance approves a pending refund. PENDING → APPROVED.
250	     */
251	    public function approveRefund(Refund $refund, User $approver): Refund
252	    {
253	        if ($refund->status !== RefundStatus::PENDING) {
254	            throw new RuntimeException('Only PENDING refunds can be approved.', 422);
255	        }
256	
257	        return DB::transaction(function () use ($refund, $approver) {
258	            $before         = ['status' => $refund->status->value];
259	            $refund->status      = RefundStatus::APPROVED;
260	            $refund->approved_by = $approver->id;
261	            $refund->saveWithLock();
262	
263	            AuditService::record('refund.approved', 'Refund', $refund->id, $before, [
264	                'status'      => RefundStatus::APPROVED->value,
265	                'approved_by' => $approver->id,
266	            ]);
267	
268	            return $refund->fresh();
269	        });
270	    }
271	
272	    /**
273	     * Process an approved refund. APPROVED → PROCESSED.
274	     * Full refund  → order REFUNDED, expires_at = now (terminates membership).
275	     * Partial      → order PARTIALLY_REFUNDED, membership stays active.
276	     */
277	    public function processRefund(Refund $refund): Refund
278	    {
279	        if ($refund->status !== RefundStatus::APPROVED) {
280	            throw new RuntimeException('Only APPROVED refunds can be processed.', 422);
281	        }
282	
283	        return DB::transaction(function () use ($refund) {
284	            $before              = ['status' => $refund->status->value];
285	            $refund->status      = RefundStatus::PROCESSED;
286	            $refund->processed_at = now();
287	            $refund->saveWithLock();
288	
289	            // Find the order linked via payment
290	            $order = MembershipOrder::where('payment_id', $refund->payment_id)->first();
291	
292	            if ($order) {
293	                $orderBefore = ['status' => $order->status->value];
294	
295	                if ($refund->refund_type === RefundType::FULL) {
296	                    // questions.md 3.3: full refund terminates the membership immediately
297	                    $order->status     = OrderStatus::REFUNDED;
298	                    $order->expires_at = now();
299	                } else {
300	                    // Partial: membership stays active
301	                    $order->status = OrderStatus::PARTIALLY_REFUNDED;
302	                }
303	
304	                $order->saveWithLock();
305	
306	                AuditService::record('membership_order.refund_applied', 'MembershipOrder', $order->id, $orderBefore, [
307	                    'status'      => $order->status->value,
308	                    'refund_type' => $refund->refund_type->value,
309	                ]);
310	            }
311	
312	            AuditService::record('refund.processed', 'Refund', $refund->id, $before, [
313	                'status'       => RefundStatus::PROCESSED->value,
314	                'processed_at' => now()->toIso8601String(),
315	            ]);
316	
317	            return $refund->fresh();
318	        });
319	    }
