3	namespace App\Services;
4	
5	use App\Enums\CaseAction;
6	use App\Enums\CaseStatus;
7	use App\Enums\CredentialingStatus;
8	use App\Models\CredentialingCase;
9	use App\Models\Doctor;
10	use App\Models\User;
11	use App\Services\AuditService;
12	use Illuminate\Support\Str;
13	use RuntimeException;
14	
15	class CredentialingService
16	{
17	    // ── Submit ────────────────────────────────────────────────────────────────
18	
19	    /**
20	     * CRED-01: Requires LICENSE + BOARD_CERTIFICATION.
21	     * questions.md 2.1: Only one active case per doctor.
22	     *
23	     * Participates in the universal service-layer idempotency contract
24	     * (`docs/design.md:70-73`, audit Issue 3). The natural-key guard
25	     * (`activeCase() !== null`) still protects against logically-duplicate
26	     * submissions, but an explicit `$idempotencyKey` makes retries of the
27	     * *same* submission deterministic: they return the case that was already
28	     * created instead of 422-ing on the natural-key guard.
29	     */
30	    public function submitCase(Doctor $doctor, User $actor, string $idempotencyKey): CredentialingCase
31	    {
32	        $existingByKey = CredentialingCase::where('idempotency_key', $idempotencyKey)->first();
33	        if ($existingByKey) {
34	            return $existingByKey;
35	        }
36	
37	        if (! $doctor->credentialing_status->canSubmitNewCase()) {
38	            throw new RuntimeException(
39	                'A case cannot be submitted while the doctor status is ' . $doctor->credentialing_status->label() . '.',
40	                422,
41	            );
42	        }
43	
44	        if ($doctor->activeCase() !== null) {
45	            throw new RuntimeException('This doctor already has an active credentialing case.', 422);
46	        }
47	
48	        if (! $doctor->hasRequiredDocuments()) {
49	            throw new RuntimeException(
50	                'Submission requires both a Medical License and Board Certification document.',
51	                422,
52	            );
53	        }
54	
55	        $case = CredentialingCase::create([
56	            'doctor_id'       => $doctor->id,
57	            'status'          => CaseStatus::SUBMITTED->value,
58	            'submitted_at'    => now(),
59	            'version'         => 1,
60	            'idempotency_key' => $idempotencyKey,
61	        ]);
62	
63	        $this->recordAction($case, CaseAction::SUBMIT, $actor);
64	
65	        $doctor->transitionCredentialingStatus(CredentialingStatus::UNDER_REVIEW);
66	
67	        AuditService::record('credentialing.case_submitted', 'CredentialingCase', $case->id, null, [
68	            'doctor_id' => $doctor->id,
69	        ]);
70	
71	        return $case->fresh();
72	    }
73	
74	    // ── Assign reviewer ───────────────────────────────────────────────────────
75	
76	    /** CRED-04: Case must be assigned before review starts. */
77	    public function assignReviewer(CredentialingCase $case, User $reviewer, User $actor): void
78	    {
79	        if ($case->status !== CaseStatus::SUBMITTED) {
80	            throw new RuntimeException('Reviewer can only be assigned on SUBMITTED cases.', 422);
81	        }
82	
83	        $case->forceFill(['assigned_reviewer' => $reviewer->id])->save();
84	
85	        $this->recordAction($case, CaseAction::ASSIGN, $actor, "Assigned to {$reviewer->username}");
86	    }
87	
88	    // ── Start review ──────────────────────────────────────────────────────────
89	
90	    public function startReview(CredentialingCase $case, User $actor): void
91	    {
92	        $this->assertTransition($case, CaseStatus::INITIAL_REVIEW);
93	
94	        if ($case->assigned_reviewer === null) {
95	            throw new RuntimeException('A reviewer must be assigned before review can start.', 422);
96	        }
97	
98	        $this->assertActorCanAct($case, $actor);
99	
100	        $case->status = CaseStatus::INITIAL_REVIEW;
101	        $case->saveWithLock();
102	
103	        $this->recordAction($case, CaseAction::START_REVIEW, $actor);
104	    }
105	
106	    // ── Request materials ─────────────────────────────────────────────────────
107	
108	    /**
109	     * CRED-05: Returns case to doctor with notes; doctor must upload and resubmit.
110	     */
111	    public function requestMaterials(CredentialingCase $case, User $actor, string $notes): void
112	    {
113	        $this->assertTransition($case, CaseStatus::MORE_MATERIALS_REQUESTED);
114	        $this->assertActorCanAct($case, $actor);
115	
116	        $case->status = CaseStatus::MORE_MATERIALS_REQUESTED;
117	        $case->saveWithLock();
118	
119	        $this->recordAction($case, CaseAction::REQUEST_MATERIALS, $actor, $notes);
120	
121	        // Sync doctor status
122	        $case->doctor->transitionCredentialingStatus(CredentialingStatus::MORE_MATERIALS_REQUESTED);
123	    }
124	
125	    // ── Receive materials ─────────────────────────────────────────────────────
126	
127	    /**
128	     * Called after doctor uploads new docs and clicks "Resubmit".
129	     * Transitions case → RE_REVIEW, doctor → UNDER_REVIEW.
130	     */
131	    public function receiveMaterials(CredentialingCase $case, User $actor): void
132	    {
133	        $this->assertTransition($case, CaseStatus::RE_REVIEW);
134	
135	        $case->status = CaseStatus::RE_REVIEW;
136	        $case->saveWithLock();
137	
138	        $this->recordAction($case, CaseAction::RECEIVE_MATERIALS, $actor);
139	
140	        $case->doctor->transitionCredentialingStatus(CredentialingStatus::UNDER_REVIEW);
141	    }
142	
143	    // ── Approve ───────────────────────────────────────────────────────────────
144	
145	    /**
146	     * CRED-06: Case → APPROVED, doctor → APPROVED, activated_at = now.
147	     */
148	    public function approve(CredentialingCase $case, User $actor): void
149	    {
150	        $this->assertTransition($case, CaseStatus::APPROVED);
151	        $this->assertActorCanAct($case, $actor);
152	
153	        $case->status      = CaseStatus::APPROVED;
154	        $case->resolved_at = now();
155	        $case->saveWithLock();
156	
157	        $this->recordAction($case, CaseAction::APPROVE, $actor);
158	
159	        $case->doctor->transitionCredentialingStatus(CredentialingStatus::APPROVED);
160	    }
161	
162	    // ── Reject ────────────────────────────────────────────────────────────────
163	
164	    /**
165	     * CRED-07: Terminal for this case. Doctor can open a new one.
166	     */
167	    public function reject(CredentialingCase $case, User $actor, string $notes): void
168	    {
169	        $this->assertTransition($case, CaseStatus::REJECTED);
170	        $this->assertActorCanAct($case, $actor);
171	
172	        $case->status      = CaseStatus::REJECTED;
173	        $case->resolved_at = now();
174	        $case->saveWithLock();
175	
176	        $this->recordAction($case, CaseAction::REJECT, $actor, $notes);
177	
178	        $case->doctor->transitionCredentialingStatus(CredentialingStatus::REJECTED);
179	    }
180	
181	    // ── Internals ─────────────────────────────────────────────────────────────
182	
183	    private function assertTransition(CredentialingCase $case, CaseStatus $target): void
184	    {
185	        if (! in_array($target, $case->status->allowedTransitions(), true)) {
186	            throw new RuntimeException(
187	                "Cannot transition case from {$case->status->label()} to {$target->label()}.",
188	                422,
189	            );
190	        }
191	    }
192	
193	    /**
194	     * Object-level authorization guard: the role check in the Livewire mount
195	     * method only proves the actor is *a* reviewer, not the one assigned to
196	     * THIS case. Without this gate, any reviewer could approve/reject/
197	     * request-materials on a case they were not assigned to.
198	     *
199	     * Admins bypass via `CredentialingCase::canBeActedOnBy()`. State-changing
200	     * actions (startReview/requestMaterials/approve/reject) are the ones
201	     * guarded. `assignReviewer` is intentionally not guarded here because
202	     * assignment is an administrative step that happens *before* any reviewer
203	     * is attached; `receiveMaterials` is triggered by the doctor resubmitting,
204	     * not by a reviewer.
205	     */
206	    private function assertActorCanAct(CredentialingCase $case, User $actor): void
207	    {
208	        if (! $case->canBeActedOnBy($actor)) {
209	            throw new RuntimeException(
210	                'You are not the reviewer assigned to this case.',
211	                403,
212	            );
213	        }
214	    }
215	
216	    private function recordAction(
217	        CredentialingCase $case,
218	        CaseAction        $action,
219	        User              $actor,
220	        ?string           $notes = null,
221	    ): void {
222	        $case->actions()->create([
223	            'action'    => $action->value,
224	            'actor_id'  => $actor->id,
225	            'notes'     => $notes,
226	            'timestamp' => now(),
227	        ]);
228	    }
229	}
