3	namespace App\Services;
4	
5	use App\Enums\ExceptionStatus;
6	use App\Enums\ExceptionType;
7	use App\Enums\PaymentStatus;
8	use App\Enums\RefundStatus;
9	use App\Enums\SettlementStatus;
10	use App\Models\Payment;
11	use App\Models\Refund;
12	use App\Models\Settlement;
13	use App\Models\SettlementException;
14	use App\Models\User;
15	use Carbon\Carbon;
16	use Illuminate\Support\Facades\DB;
17	use Illuminate\Support\Facades\Storage;
18	use RuntimeException;
19	
20	class SettlementService
21	{
22	    // ── Close daily settlement ─────────────────────────────────────────────────
23	
24	    /**
25	     * Compute and close the daily settlement for $date.
26	     * FIN-06: variance > $0.01 → EXCEPTION status + exception record.
27	     * FIN-07: |variance| <= 1 cent → RECONCILED.
28	     */
29	    public function closeDailySettlement(Carbon|string $date): Settlement
30	    {
31	        $date = Carbon::parse($date)->toDateString();
32	
33	        return DB::transaction(function () use ($date) {
34	            // Find or create the settlement for this date
35	            $settlement = Settlement::firstOrCreate(
36	                ['settlement_date' => $date],
37	                [
38	                    'status'                => SettlementStatus::OPEN->value,
39	                    'total_payments_cents'  => 0,
40	                    'total_refunds_cents'   => 0,
41	                    'net_amount_cents'      => 0,
42	                    'expected_amount_cents' => 0,
43	                    'variance_cents'        => 0,
44	                    'version'               => 1,
45	                ]
46	            );
47	
48	            if ($settlement->status === SettlementStatus::RECONCILED) {
49	                throw new RuntimeException('Settlement is already reconciled.', 409);
50	            }
51	
52	            // Sum CONFIRMED payments for this date
53	            $totalPayments = (int) Payment::where('status', PaymentStatus::CONFIRMED->value)
54	                ->whereDate('confirmed_at', $date)
55	                ->sum('amount_cents');
56	
57	            // Sum PROCESSED refunds for this date
58	            $totalRefunds = (int) Refund::where('status', RefundStatus::PROCESSED->value)
59	                ->whereDate('processed_at', $date)
60	                ->sum('amount_cents');
61	
62	            $net      = $totalPayments - $totalRefunds;
63	            $expected = $settlement->expected_amount_cents;
64	            $variance = $net - $expected;
65	
66	            $settlement->total_payments_cents = $totalPayments;
67	            $settlement->total_refunds_cents  = $totalRefunds;
68	            $settlement->net_amount_cents     = $net;
69	            $settlement->variance_cents       = $variance;
70	            $settlement->closed_at            = now();
71	
72	            // Link all included payments
73	            Payment::where('status', PaymentStatus::CONFIRMED->value)
74	                ->whereDate('confirmed_at', $date)
75	                ->whereNull('settlement_id')
76	                ->update(['settlement_id' => $settlement->id]);
77	
78	            // Determine status: FIN-07 vs FIN-06
79	            if (abs($variance) <= 1) {
80	                $settlement->status         = SettlementStatus::RECONCILED;
81	                $settlement->reconciled_at  = now();
82	            } else {
83	                $settlement->status = SettlementStatus::EXCEPTION;
84	
85	                SettlementException::create([
86	                    'settlement_id'   => $settlement->id,
87	                    'exception_type'  => ExceptionType::VARIANCE->value,
88	                    'description'     => sprintf(
89	                        'Settlement variance of %s detected. Expected %s, got %s.',
90	                        formatCurrency(abs($variance)),
91	                        formatCurrency($expected),
92	                        formatCurrency($net)
93	                    ),
94	                    'amount_cents'    => $variance,
95	                    'status'          => ExceptionStatus::OPEN->value,
96	                    'version'         => 1,
97	                ]);
98	            }
99	
100	            // Generate statement CSV
101	            $filePath = $this->generateStatementFile($settlement, $date);
102	            $settlement->statement_file_path = $filePath;
103	
104	            $settlement->saveWithLock();
105	
106	            AuditService::record('settlement.closed', 'Settlement', $settlement->id, null, [
107	                'date'                => $date,
108	                'total_payments'      => $totalPayments,
109	                'total_refunds'       => $totalRefunds,
110	                'variance_cents'      => $variance,
111	                'status'              => $settlement->status->value,
112	            ]);
113	
114	            return $settlement->fresh();
115	        });
116	    }
117	
118	    // ── Resolve exception ─────────────────────────────────────────────────────
119	
120	    /**
121	     * Resolve or write-off an OPEN exception.
122	     */
123	    public function resolveException(
124	        SettlementException $exception,
125	        ExceptionStatus $resolution,
126	        string $notes,
127	        User $resolver
128	    ): SettlementException {
129	        if ($exception->status !== ExceptionStatus::OPEN) {
130	            throw new RuntimeException('Exception is already resolved.', 409);
131	        }
132	
133	        if (! in_array($resolution, [ExceptionStatus::RESOLVED, ExceptionStatus::WRITTEN_OFF], true)) {
134	            throw new RuntimeException('Resolution must be RESOLVED or WRITTEN_OFF.', 422);
135	        }
136	
137	        return DB::transaction(function () use ($exception, $resolution, $notes, $resolver) {
138	            $exception->status          = $resolution;
139	            $exception->resolved_by     = $resolver->id;
140	            $exception->resolution_note = $notes;
141	            $exception->save();
142	
143	            AuditService::record('settlement_exception.resolved', 'SettlementException', $exception->id, null, [
144	                'resolution' => $resolution->value,
145	                'notes'      => $notes,
146	            ]);
147	
148	            return $exception;
149	        });
150	    }
151	
152	    // ── Re-reconcile ──────────────────────────────────────────────────────────
153	
154	    /**
155	     * If all exceptions on a settlement are resolved, transition it to RECONCILED.
156	     */
157	    public function reReconcile(Settlement $settlement): Settlement
158	    {
159	        if ($settlement->status !== SettlementStatus::EXCEPTION) {
160	            throw new RuntimeException('Only EXCEPTION settlements can be re-reconciled.', 422);
161	        }
162	
163	        $openExceptions = $settlement->exceptions()
164	            ->where('status', ExceptionStatus::OPEN->value)
165	            ->count();
166	
167	        if ($openExceptions > 0) {
168	            throw new RuntimeException(
169	                "Cannot reconcile: {$openExceptions} open exception(s) remain.",
170	                422
171	            );
172	        }
173	
174	        return DB::transaction(function () use ($settlement) {
175	            $settlement->status        = SettlementStatus::RECONCILED;
176	            $settlement->reconciled_at = now();
177	            $settlement->saveWithLock();
178	
179	            AuditService::record('settlement.reconciled', 'Settlement', $settlement->id, null, [
180	                'status' => SettlementStatus::RECONCILED->value,
181	            ]);
182	
183	            return $settlement->fresh();
184	        });
185	    }
186	
187	    // ── Export statement ──────────────────────────────────────────────────────
188	
189	    /**
190	     * Return the storage path of the settlement's statement file, generating
191	     * it if needed.
192	     *
193	     * Every call records an audit entry (audit Issue 5). The entry captures
194	     * the acting user via AuditService → auth()->id(), the settlement id,
195	     * the file path, and whether the file had to be (re)generated. This
196	     * closes the end-to-end export traceability gap called out in the
197	     * prompt.
198	     */
199	    public function exportStatement(Settlement $settlement): string
200	    {
201	        if ($settlement->statement_file_path && Storage::disk('local')->exists($settlement->statement_file_path)) {
202	            $path       = $settlement->statement_file_path;
203	            $regenerated = false;
204	        } else {
205	            $path       = $this->generateStatementFile($settlement, $settlement->settlement_date->toDateString());
206	            $regenerated = true;
207	        }
208	
209	        AuditService::record(
210	            action:     'settlement.statement_exported',
211	            entityType: 'Settlement',
212	            entityId:   $settlement->id,
213	            before:     null,
214	            after:      [
215	                'settlement_date' => $settlement->settlement_date->toDateString(),
216	                'file_path'       => $path,
217	                'regenerated'     => $regenerated,
218	            ],
219	        );
220	
221	        return $path;
222	    }
223	
224	    // ── Private ───────────────────────────────────────────────────────────────
225	
226	    private function generateStatementFile(Settlement $settlement, string $date): string
227	    {
228	        $dir  = 'statements';
229	        $file = "{$dir}/settlement-{$date}.csv";
230	
231	        Storage::disk('local')->makeDirectory($dir);
232	
233	        $payments = Payment::where('settlement_id', $settlement->id)
234	            ->with('user')
235	            ->get();
236	
237	        $lines = ["id,user_email,tender_type,amount_cents,confirmed_at,reference_number"];
238	        foreach ($payments as $p) {
239	            $lines[] = implode(',', [
240	                $p->id,
241	                $p->user?->email ?? '',
242	                $p->tender_type->value,
243	                $p->amount_cents,
244	                $p->confirmed_at?->toDateTimeString() ?? '',
245	                $p->reference_number ?? '',
246	            ]);
247	        }
248	
249	        $lines[] = "";
250	        $lines[] = "Summary";
251	        $lines[] = "total_payments_cents,{$settlement->total_payments_cents}";
252	        $lines[] = "total_refunds_cents,{$settlement->total_refunds_cents}";
253	        $lines[] = "net_amount_cents,{$settlement->net_amount_cents}";
254	        $lines[] = "variance_cents,{$settlement->variance_cents}";
255	        $lines[] = "status,{$settlement->status->value}";
256	
257	        Storage::disk('local')->put($file, implode("\n", $lines));
258	
259	        return $file;
260	    }
261	}
