namespace App\Http\Controllers\Api;

use App\Http\Controllers\Controller;
use App\Models\Trip;
use App\Models\TripSignup;
use App\Services\SeatService;
use App\Services\WaitlistService;
use Illuminate\Http\JsonResponse;
use Illuminate\Http\Request;
use Illuminate\Support\Str;
use RuntimeException;

/**
 * REST endpoints for trip seat signup and waitlist.
 *
 * These controllers are thin wrappers over the service layer so that the
 * same business logic is reachable from both Livewire components (via the
 * normal web session) and from any future API consumer.
 *
 * Routes:
 *   POST   /api/v1/trips/{trip}/signups            → holdSeat
 *   DELETE /api/v1/trips/{trip}/signups/{signup}   → cancelSignup
 *   POST   /api/v1/trips/{trip}/waitlist           → joinWaitlist
 */
class TripSignupController extends Controller
{
    public function __construct(
        private readonly SeatService     $seatService,
        private readonly WaitlistService $waitlistService,
    ) {}

    /** POST /api/v1/trips/{trip}/signups — hold a seat */
    public function hold(Request $request, Trip $trip): JsonResponse
    {
        $idempotencyKey = $request->header('X-Idempotency-Key') ?? (string) Str::uuid();

        try {
            $signup = $this->seatService->holdSeat($trip, $request->user(), $idempotencyKey);
        } catch (RuntimeException $e) {
            return response()->json(['message' => $e->getMessage()], $e->getCode() ?: 422);
        }

        return response()->json($signup, 201);
    }

    /** DELETE /api/v1/trips/{trip}/signups/{signup} — cancel a confirmed signup */
    public function cancel(Request $request, Trip $trip, TripSignup $signup): JsonResponse
    {
        if ($signup->trip_id !== $trip->id) {
            return response()->json(['message' => 'Signup does not belong to this trip.'], 422);
        }

        if ($signup->user_id !== $request->user()->id && ! $request->user()->isAdmin()) {
            return response()->json(['message' => 'Forbidden.'], 403);
        }

        try {
            $this->seatService->cancelConfirmedSignup($signup);
        } catch (RuntimeException $e) {
            return response()->json(['message' => $e->getMessage()], $e->getCode() ?: 422);
        }

        return response()->json(null, 204);
    }

    /** POST /api/v1/trips/{trip}/waitlist — join the waitlist */
    public function joinWaitlist(Request $request, Trip $trip): JsonResponse
    {
        $idempotencyKey = $request->header('X-Idempotency-Key') ?? (string) Str::uuid();

        try {
            $entry = $this->waitlistService->joinWaitlist($trip, $request->user(), $idempotencyKey);
        } catch (RuntimeException $e) {
            return response()->json(['message' => $e->getMessage()], $e->getCode() ?: 422);
        }

        return response()->json($entry, 201);
    }
}
