namespace App\Http\Controllers\Api;

use App\Http\Controllers\Controller;
use App\Models\AuditLog;
use Illuminate\Http\JsonResponse;
use Illuminate\Http\Request;

/**
 * REST endpoint for audit log search.
 *
 * Routes:
 *   GET /api/v1/audit-logs   → index
 */
class AuditController extends Controller
{
    /**
     * GET /api/v1/audit-logs
     *
     * Filterable by: action, entity_type, entity_id, actor_id, date_from, date_to.
     * Always ordered by created_at DESC. Paginated (50 per page).
     * Restricted to ADMIN.
     */
    public function index(Request $request): JsonResponse
    {
        $request->validate([
            'action'      => 'nullable|string|max:128',
            'entity_type' => 'nullable|string|max:128',
            'entity_id'   => 'nullable|uuid',
            'actor_id'    => 'nullable|uuid',
            'date_from'   => 'nullable|date_format:Y-m-d',
            'date_to'     => 'nullable|date_format:Y-m-d|after_or_equal:date_from',
        ]);

        $query = AuditLog::query()
            ->orderByDesc('created_at')
            ->orderByDesc('id');

        if ($request->filled('action')) {
            $query->where('action', 'like', '%' . $request->input('action') . '%');
        }
        if ($request->filled('entity_type')) {
            $query->where('entity_type', $request->input('entity_type'));
        }
        if ($request->filled('entity_id')) {
            $query->where('entity_id', $request->input('entity_id'));
        }
        if ($request->filled('actor_id')) {
            $query->where('actor_id', $request->input('actor_id'));
        }
        if ($request->filled('date_from')) {
            $query->whereDate('created_at', '>=', $request->input('date_from'));
        }
        if ($request->filled('date_to')) {
            $query->whereDate('created_at', '<=', $request->input('date_to'));
        }

        $results = $query->paginate(50);

        return response()->json($results);
    }
}
"}

