use App\Http\Controllers\Api\AuditController;
use App\Http\Controllers\Api\CredentialingController;
use App\Http\Controllers\Api\InvoiceController;
use App\Http\Controllers\Api\MembershipController;
use App\Http\Controllers\Api\PaymentController;
use App\Http\Controllers\Api\SettlementController;
use App\Http\Controllers\Api\TripSignupController;
use Illuminate\Support\Facades\Route;

/*
|--------------------------------------------------------------------------
| API Routes — MedVoyage REST Contract (v1)
|--------------------------------------------------------------------------
|
| These endpoints expose the same service-layer logic consumed by Livewire
| components over the web session. They satisfy the prompt's explicit
| requirement for "REST-style endpoints" and allow future API consumers
| (mobile apps, third-party integrations, automated tooling) to interact
| with the system without going through the Livewire wire-protocol.
|
| Auth: session-based (same cookie as the web app; Sanctum SPA mode) or
| token-based (Sanctum API tokens). The `auth:sanctum` middleware covers
| both. Role gates are enforced inside each controller, mirroring the
| route middleware groups in routes/web.php.
|
| Idempotency: all mutating endpoints accept an optional
| `X-Idempotency-Key` header. If provided, the service layer short-circuits
| on duplicate requests and returns the existing result without side effects.
| See `app/Services/IdempotencyStore.php` for the implementation contract.
|
| Error conventions (matching the web app — see docs/api-spec.md):
|   403  Role/ownership gate failed
|   404  Resource not found (model binding)
|   409  Stale version (optimistic lock) or idempotency conflict
|   422  Business rule violated (invalid transition, validation failure)
|
*/

Route::middleware(['auth:sanctum', 'account.status'])->prefix('v1')->group(function () {

    // ── Trip signups & waitlist ───────────────────────────────────────────────
    Route::post('/trips/{trip}/signups',           [TripSignupController::class, 'hold']);
    Route::delete('/trips/{trip}/signups/{signup}', [TripSignupController::class, 'cancel']);
    Route::post('/trips/{trip}/waitlist',           [TripSignupController::class, 'joinWaitlist']);

    // ── Credentialing ─────────────────────────────────────────────────────────
    Route::post('/credentialing/cases',                              [CredentialingController::class, 'submit']);
    Route::patch('/credentialing/cases/{case}/assign',              [CredentialingController::class, 'assignReviewer']);
    Route::patch('/credentialing/cases/{case}/start-review',        [CredentialingController::class, 'startReview']);
    Route::patch('/credentialing/cases/{case}/request-materials',   [CredentialingController::class, 'requestMaterials']);
    Route::patch('/credentialing/cases/{case}/receive-materials',   [CredentialingController::class, 'receiveMaterials']);
    Route::patch('/credentialing/cases/{case}/approve',             [CredentialingController::class, 'approve']);
    Route::patch('/credentialing/cases/{case}/reject',              [CredentialingController::class, 'reject']);

    // ── Membership & refunds ──────────────────────────────────────────────────
    Route::post('/membership/orders',                        [MembershipController::class, 'purchase']);
    Route::post('/membership/orders/{order}/refund',         [MembershipController::class, 'requestRefund']);
    Route::middleware('finance')->group(function () {
        Route::patch('/membership/refunds/{refund}/approve', [MembershipController::class, 'approveRefund']);
        Route::patch('/membership/refunds/{refund}/process', [MembershipController::class, 'processRefund']);
    });

    // ── Payments ──────────────────────────────────────────────────────────────
    Route::middleware('finance')->group(function () {
        Route::post('/payments',                    [PaymentController::class, 'record']);
        Route::patch('/payments/{payment}/confirm', [PaymentController::class, 'confirm']);
        Route::patch('/payments/{payment}/void',    [PaymentController::class, 'void']);
    });

    // ── Settlements ───────────────────────────────────────────────────────────
    Route::middleware('finance')->group(function () {
        Route::post('/settlements/close',                                [SettlementController::class, 'close']);
        Route::patch('/settlements/{settlement}/reconcile',              [SettlementController::class, 'reReconcile']);
        Route::patch('/settlement-exceptions/{exception}/resolve',       [SettlementController::class, 'resolveException']);
    });

    // ── Invoices ──────────────────────────────────────────────────────────────
    Route::middleware('finance')->group(function () {
        Route::post('/invoices',                         [InvoiceController::class, 'create']);
        Route::post('/invoices/{invoice}/lines',         [InvoiceController::class, 'addLine']);
        Route::patch('/invoices/{invoice}/issue',        [InvoiceController::class, 'issue']);
        Route::patch('/invoices/{invoice}/mark-paid',    [InvoiceController::class, 'markPaid']);
        Route::patch('/invoices/{invoice}/void',         [InvoiceController::class, 'void']);
    });

    // ── Audit search (Admin only) ─────────────────────────────────────────────
    Route::middleware('admin')->group(function () {
        Route::get('/audit-logs', [AuditController::class, 'index']);
    });
});
"}

