3	namespace App\Services;
4	
5	use App\Enums\PaymentStatus;
6	use App\Enums\SignupStatus;
7	use App\Enums\TenderType;
8	use App\Models\MembershipOrder;
9	use App\Models\Payment;
10	use App\Models\TripSignup;
11	use App\Models\User;
12	use Illuminate\Support\Facades\DB;
13	use RuntimeException;
14	
15	class PaymentService
16	{
17	    // ── Record ────────────────────────────────────────────────────────────────
18	
19	    /**
20	     * Create a RECORDED payment.
21	     * Idempotent on idempotency_key.
22	     */
23	    public function recordPayment(
24	        User $user,
25	        TenderType $tenderType,
26	        int $amountCents,
27	        ?string $reference,
28	        string $idempotencyKey
29	    ): Payment {
30	        if ($existing = Payment::where('idempotency_key', $idempotencyKey)->first()) {
31	            return $existing;
32	        }
33	
34	        if ($amountCents <= 0) {
35	            throw new RuntimeException('Payment amount must be positive.', 422);
36	        }
37	
38	        return DB::transaction(function () use ($user, $tenderType, $amountCents, $reference, $idempotencyKey) {
39	            $payment = Payment::create([
40	                'user_id'          => $user->id,
41	                'tender_type'      => $tenderType->value,
42	                'amount_cents'     => $amountCents,
43	                'reference_number' => $reference,
44	                'status'           => PaymentStatus::RECORDED->value,
45	                'idempotency_key'  => $idempotencyKey,
46	                'version'          => 1,
47	            ]);
48	
49	            AuditService::record('payment.recorded', 'Payment', $payment->id, null, [
50	                'amount_cents' => $amountCents,
51	                'tender_type'  => $tenderType->value,
52	            ]);
53	
54	            return $payment;
55	        });
56	    }
57	
58	    // ── Confirm ───────────────────────────────────────────────────────────────
59	
60	    /**
61	     * Confirm a RECORDED payment. Idempotent on confirmation_event_id.
62	     */
63	    public function confirmPayment(Payment $payment, string $confirmationEventId): Payment
64	    {
65	        // Idempotency: already confirmed with this event → return as-is
66	        if ($payment->confirmation_event_id === $confirmationEventId
67	            && $payment->status === PaymentStatus::CONFIRMED) {
68	            return $payment;
69	        }
70	
71	        // Also check globally: another payment may have this event ID
72	        $existing = Payment::where('confirmation_event_id', $confirmationEventId)
73	            ->where('id', '!=', $payment->id)
74	            ->first();
75	        if ($existing) {
76	            throw new RuntimeException('This confirmation event ID is already used by another payment.', 409);
77	        }
78	
79	        if ($payment->status !== PaymentStatus::RECORDED) {
80	            throw new RuntimeException(
81	                "Cannot confirm a payment in {$payment->status->value} status.",
82	                422
83	            );
84	        }
85	
86	        return DB::transaction(function () use ($payment, $confirmationEventId) {
87	            $before = $payment->toArray();
88	
89	            $payment->status                = PaymentStatus::CONFIRMED;
90	            $payment->confirmed_at          = now();
91	            $payment->confirmation_event_id = $confirmationEventId;
92	            $payment->saveWithLock();
93	
94	            AuditService::record('payment.confirmed', 'Payment', $payment->id, $before, [
95	                'confirmation_event_id' => $confirmationEventId,
96	            ]);
97	
98	            // Wire-up: PENDING membership order → PAID.
99	            // saveWithLock() (not plain save()) so the PENDING→PAID transition
100	            // honors MembershipOrder's row-version guard. A concurrent void or
101	            // refund on the same order will surface as StaleRecordException
102	            // rather than silently clobbering a terminal state.
103	            $order = MembershipOrder::where('payment_id', $payment->id)->first();
104	            if ($order && $order->status->value === 'PENDING') {
105	                $order->status = \App\Enums\OrderStatus::PAID;
106	                $order->saveWithLock();
107	                AuditService::record('membership_order.paid', 'MembershipOrder', $order->id, null, [
108	                    'payment_id' => $payment->id,
109	                ]);
110	            }
111	
112	            return $payment;
113	        });
114	    }
115	
116	    // ── Void ──────────────────────────────────────────────────────────────────
117	
118	    /**
119	     * Void a payment. Cascades to cancel linked trip signup or membership order.
120	     * questions.md 4.5: RECORDED or CONFIRMED → VOIDED.
121	     */
122	    public function voidPayment(Payment $payment): Payment
123	    {
124	        if (! in_array($payment->status, [PaymentStatus::RECORDED, PaymentStatus::CONFIRMED], true)) {
125	            throw new RuntimeException(
126	                "Cannot void a payment in {$payment->status->value} status.",
127	                422
128	            );
129	        }
130	
131	        return DB::transaction(function () use ($payment) {
132	            $before = $payment->toArray();
133	
134	            $payment->status = PaymentStatus::VOIDED;
135	            $payment->saveWithLock();
136	
137	            // Cascade: cancel linked trip signup
138	            $signup = TripSignup::where('payment_id', $payment->id)->first();
139	            if ($signup && ! in_array($signup->status, [SignupStatus::CANCELLED, SignupStatus::EXPIRED], true)) {
140	                $seatService = app(SeatService::class);
141	                if ($signup->status === SignupStatus::CONFIRMED) {
142	                    $seatService->cancelConfirmedSignup($signup);
143	                } elseif ($signup->status === SignupStatus::HOLD) {
144	                    $seatService->releaseSeat($signup, \App\Enums\HoldReleaseReason::CANCELLED);
145	                }
146	            }
147	
148	            // Cascade: cancel linked membership order.
149	            // saveWithLock() so a race with a concurrent refund / top-up /
150	            // PENDING→PAID transition on the same order surfaces as a
151	            // StaleRecordException instead of silently overwriting.
152	            $order = MembershipOrder::where('payment_id', $payment->id)->first();
153	            if ($order && ! in_array($order->status, [\App\Enums\OrderStatus::REFUNDED, \App\Enums\OrderStatus::VOIDED], true)) {
154	                $order->status = \App\Enums\OrderStatus::VOIDED;
155	                $order->saveWithLock();
156	            }
157	
158	            AuditService::record('payment.voided', 'Payment', $payment->id, $before, [
159	                'status' => PaymentStatus::VOIDED->value,
160	            ]);
161	
162	            return $payment;
163	        });
164	    }
165	}
