3	namespace App\Services;
4	
5	use App\Enums\SignupStatus;
6	use App\Enums\WaitlistStatus;
7	use App\Events\WaitlistOfferMade;
8	use App\Jobs\ExpireWaitlistOfferJob;
9	use App\Models\Trip;
10	use App\Models\TripWaitlistEntry;
11	use App\Models\User;
12	use App\Services\AuditService;
13	use Illuminate\Support\Facades\DB;
14	use RuntimeException;
15	
16	class WaitlistService
17	{
18	    /**
19	     * Join the waitlist for a trip. Assigns next position.
20	     *
21	     * Participates in the universal service-layer idempotency contract:
22	     * callers MUST pass a stable `$idempotencyKey` derived from (trip, user).
23	     * Retries with the same key return the existing entry instead of
24	     * creating a second row or throwing.
25	     *
26	     * TRIP-09: one active waitlist entry per user per trip — enforced by
27	     * both the idempotency key lookup AND the (trip_id, user_id) unique
28	     * constraint on `trip_waitlist_entries` as a second line of defense.
29	     */
30	    public function joinWaitlist(Trip $trip, User $user, string $idempotencyKey): TripWaitlistEntry
31	    {
32	        // 1. Primary idempotency check: a retry with the same caller-stable key
33	        //    short-circuits to the existing row without touching any other
34	        //    indexes. Same contract as SeatService::holdSeat,
35	        //    MembershipService::purchase, PaymentService::recordPayment, etc.
36	        $existingByKey = TripWaitlistEntry::where('idempotency_key', $idempotencyKey)->first();
37	        if ($existingByKey) {
38	            return $existingByKey;
39	        }
40	
41	        // 2. Natural-key safety net: the same user may have an active entry
42	        //    created *before* the idempotency-key contract existed, or under
43	        //    a different deterministic key (e.g. tests). Return that rather
44	        //    than tripping the unique (trip_id, user_id) constraint on insert.
45	        $existingByNaturalKey = TripWaitlistEntry::where('trip_id', $trip->id)
46	            ->where('user_id', $user->id)
47	            ->whereIn('status', [WaitlistStatus::WAITING->value, WaitlistStatus::OFFERED->value])
48	            ->first();
49	
50	        if ($existingByNaturalKey) {
51	            return $existingByNaturalKey;
52	        }
53	
54	        $position = TripWaitlistEntry::where('trip_id', $trip->id)
55	            ->whereIn('status', [WaitlistStatus::WAITING->value, WaitlistStatus::OFFERED->value])
56	            ->max('position') + 1;
57	
58	        $entry = TripWaitlistEntry::create([
59	            'trip_id'         => $trip->id,
60	            'user_id'         => $user->id,
61	            'position'        => $position,
62	            'status'          => WaitlistStatus::WAITING->value,
63	            'idempotency_key' => $idempotencyKey,
64	        ]);
65	
66	        AuditService::record('waitlist.joined', 'TripWaitlistEntry', $entry->id, null, [
67	            'trip_id'  => $trip->id,
68	            'user_id'  => $user->id,
69	            'position' => $position,
70	        ]);
71	
72	        return $entry;
73	    }
74	
75	    /**
76	     * TRIP-07: Offer a seat to the next WAITING entry (FIFO by position).
77	     * Called after a seat is released. No-op if no waitlist or trip is not PUBLISHED/FULL.
78	     */
79	    public function offerNextSeat(Trip $trip): void
80	    {
81	        $entry = TripWaitlistEntry::where('trip_id', $trip->id)
82	            ->where('status', WaitlistStatus::WAITING->value)
83	            ->orderBy('position')
84	            ->first();
85	
86	        if (! $entry) {
87	            return;
88	        }
89	
90	        $offerMinutes  = (int) config('medvoyage.waitlist_offer_minutes', 10);
91	        $offerExpiresAt = now()->addMinutes($offerMinutes);
92	
93	        $before = ['status' => $entry->status->value];
94	
95	        $entry->status          = WaitlistStatus::OFFERED;
96	        $entry->offered_at      = now();
97	        $entry->offer_expires_at = $offerExpiresAt;
98	        $entry->save();
99	
100	        AuditService::record('waitlist.offer_made', 'TripWaitlistEntry', $entry->id, $before, [
101	            'status'          => WaitlistStatus::OFFERED->value,
102	            'offer_expires_at' => $offerExpiresAt->toIso8601String(),
103	        ]);
104	
105	        WaitlistOfferMade::dispatch($trip, $entry);
106	
107	        // Real-time expiry: schedule the 10-minute offer window as a delayed
108	        // queue job instead of relying on the every-minute polling command.
109	        // See docs/questions.md §1.4. Dispatched directly (not via
110	        // afterCommit) so RefreshDatabase-wrapped tests still see the
111	        // dispatch; the job re-fetches the entry on execution and no-ops if
112	        // the enclosing transaction rolled back in production.
113	        ExpireWaitlistOfferJob::dispatch($entry->id)->delay($offerExpiresAt);
114	    }
115	
116	    /**
117	     * Accept a waitlist offer — creates a seat hold for the user.
118	     * SeatService resolved from container to avoid circular constructor injection.
119	     */
120	    public function acceptOffer(TripWaitlistEntry $entry, string $idempotencyKey): \App\Models\TripSignup
121	    {
122	        if ($entry->status !== WaitlistStatus::OFFERED) {
123	            throw new RuntimeException('No active offer to accept.', 422);
124	        }
125	
126	        if ($entry->isOfferExpired()) {
127	            throw new RuntimeException('Offer has expired.', 422);
128	        }
129	
130	        return DB::transaction(function () use ($entry, $idempotencyKey) {
131	            $before = ['status' => $entry->status->value];
132	
133	            $entry->status = WaitlistStatus::ACCEPTED;
134	            $entry->save();
135	
136	            AuditService::record('waitlist.offer_accepted', 'TripWaitlistEntry', $entry->id, $before, [
137	                'status' => WaitlistStatus::ACCEPTED->value,
138	            ]);
139	
140	            $user        = $entry->user;
141	            $trip        = $entry->trip;
142	            $seatService = app(SeatService::class);
143	
144	            return $seatService->holdSeat($trip, $user, $idempotencyKey);
145	        });
146	    }
147	
148	    /**
149	     * Decline a waitlist offer — moves entry to DECLINED and offers to next in line.
150	     */
151	    public function declineOffer(TripWaitlistEntry $entry): void
152	    {
153	        if ($entry->status !== WaitlistStatus::OFFERED) {
154	            throw new RuntimeException('No active offer to decline.', 422);
155	        }
156	
157	        DB::transaction(function () use ($entry) {
158	            $before = ['status' => $entry->status->value];
159	
160	            $entry->status = WaitlistStatus::DECLINED;
161	            $entry->save();
162	
163	            AuditService::record('waitlist.offer_declined', 'TripWaitlistEntry', $entry->id, $before, [
164	                'status' => WaitlistStatus::DECLINED->value,
165	            ]);
166	
167	            $this->offerNextSeat($entry->trip);
168	        });
169	    }
170	
171	    /**
172	     * Expire an offer that was not accepted in time.
173	     */
174	    public function expireOffer(TripWaitlistEntry $entry): void
175	    {
176	        if ($entry->status !== WaitlistStatus::OFFERED) {
177	            return;
178	        }
179	
180	        DB::transaction(function () use ($entry) {
181	            $before = ['status' => $entry->status->value];
182	
183	            $entry->status = WaitlistStatus::EXPIRED;
184	            $entry->save();
185	
186	            AuditService::record('waitlist.offer_expired', 'TripWaitlistEntry', $entry->id, $before, [
187	                'status' => WaitlistStatus::EXPIRED->value,
188	            ]);
189	
190	            $this->offerNextSeat($entry->trip);
191	        });
192	    }
193	}
