    public function approveRefund(Refund $refund, User $approver, ?string $idempotencyKey = null): Refund
    {
        $store = new IdempotencyStore();
        if ($idempotencyKey && $store->alreadyProcessed($idempotencyKey, 'refund.approve', $refund->id)) {
            return $refund->fresh();
