    public function confirm(Request $request, Payment $payment): JsonResponse
    {
        // `confirmation_event_id` is the domain idempotency token for this
        // operation (it must be unique per payment-gateway event). Callers
        // may supply it either in the request body OR as the standard
        // X-Idempotency-Key header so the contract is uniform across all
        // mutating endpoints. Body wins when both are present.
        $request->validate([
            'confirmation_event_id' => 'nullable|string|max:255',
        ]);

        $confirmationEventId = $request->input('confirmation_event_id')
            ?? $request->header('X-Idempotency-Key');

        if (! $confirmationEventId) {
            return response()->json([
                'message' => 'A confirmation_event_id body field or X-Idempotency-Key header is required.',
            ], 422);
        }

        try {
            $payment = $this->service->confirmPayment($payment, $confirmationEventId);
        } catch (RuntimeException $e) {
            return response()->json(['message' => $e->getMessage()], $e->getCode() ?: 422);
        }

        return response()->json($payment);
    }"}

